(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,69817,t=>{t.v({memories:[{id:"1",title:"非洲涉华情报系统架构",content:"建立了完整的非洲涉华情报收集和分析系统。包含数据抓取、内容分析、风险评估、报告生成四个核心模块。每日自动生成情报简报，支持关键词预警和事件追踪。",type:"project",tags:["情报","非洲","自动化","OSINT"],importance:5,updatedAt:"2026-02-22T20:00:00Z",createdAt:"2026-02-21T10:00:00Z"},{id:"2",title:"用户画像 - Hourglass",content:"OSINT从业者，40岁男性。专业背景：开源情报(OSINT)从业者，需要实时情报监控和数据分析，关注非洲涉华情报等特定领域。工作习惯：需要定时情报摘要，重视信息准确性和时效性，多任务并行。",type:"long_term",tags:["用户","OSINT","画像"],importance:4,updatedAt:"2026-02-21T15:30:00Z",createdAt:"2026-02-21T15:30:00Z"},{id:"3",title:"Mission Control 系统架构",content:"Next.js + Convex 技术栈的任务控制中心。包含任务看板、日历管理、记忆系统、团队视图四大模块。支持实时数据同步、拖拽交互、全局搜索等功能。",type:"system",tags:["系统","架构","Next.js","Convex"],importance:5,updatedAt:"2026-02-22T18:00:00Z",createdAt:"2026-02-22T08:00:00Z"},{id:"4",title:"美国对华政策监控数据源",content:"整理了美国对华政策监控的核心数据源：白宫官网(whitehouse.gov)、美国贸易代表办公室(USTR)、美国财政部(OFAC)、美国商务部(BIS)、美国国防部、美国国务院。以及Twitter/X监控账号清单。",type:"project",tags:["政策","美国","数据源","监控"],importance:4,updatedAt:"2026-02-22T14:00:00Z",createdAt:"2026-02-22T14:00:00Z"},{id:"5",title:"卫星遥感经济评估研究报告",content:"基于世界银行NO₂排放数据的卫星遥感经济评估研究。分析了夜间灯光数据与GDP增长的相关性，以及NO₂排放作为经济活动指标的有效性。",type:"project",tags:["卫星遥感","经济评估","NO2","世界银行"],importance:3,updatedAt:"2026-02-22T12:00:00Z",createdAt:"2026-02-22T09:00:00Z"},{id:"6",title:"Polymarket 预测市场监控",content:"Polymarket预测市场数据监控和简报生成系统。每小时抓取市场数据，分析价格变动和交易量，生成盘中简报和日报。",type:"project",tags:["市场","Polymarket","预测","简报"],importance:4,updatedAt:"2026-02-22T20:30:00Z",createdAt:"2026-02-20T10:00:00Z"},{id:"7",title:"团队组织架构 v2.0",content:"Human Director + Chief AI Officer + 5 Departments + 12 Subagents 的完整架构。部门包括：Intel(非洲情报)、Policy(中美政策)、Market(金融情报)、Engineering(工程)、Admin(记忆与管理)。",type:"system",tags:["团队","架构","组织","子代理"],importance:5,updatedAt:"2026-02-22T16:00:00Z",createdAt:"2026-02-21T11:00:00Z"},{id:"8",title:"2026-02-22 工作日志",content:"今日完成了卫星遥感报告、非洲情报系统上线、QQ邮箱配置、Task Board创建、美国对华政策监控系统搭建。多个项目并行推进，系统运行稳定。",type:"daily",tags:["日志","日报","2026-02-22"],importance:3,updatedAt:"2026-02-22T23:00:00Z",createdAt:"2026-02-22T23:00:00Z"},{id:"9",title:"UI设计规范 v21.0",content:"Mission Control UI设计规范：深色背景(#0a0a0f)、蓝色高亮(#3b82f6)、精致卡片、专业数据可视化。动画原则：流畅、克制、有意义。",type:"system",tags:["UI","设计","规范","样式"],importance:4,updatedAt:"2026-02-26T13:00:00Z",createdAt:"2026-02-26T13:00:00Z"},{id:"10",title:"定时任务调度系统",content:"基于OpenClaw Cron的定时任务调度系统。支持精确时间触发、周期性执行、任务依赖管理。当前运行任务：非洲情报简报、Polymarket监控、美国对华政策简报、QQ邮箱清理等。",type:"system",tags:["定时任务","Cron","调度","自动化"],importance:5,updatedAt:"2026-02-22T19:00:00Z",createdAt:"2026-02-22T08:00:00Z"}]})}]);